17	`include "defines.svh"
18	
19	import defines::*;
20	
21	//
22	// Instruction Pipeline Integer Execute Stage
23	// - Performs simple operations that only require a single stage like integer
24	//   addition or bitwise logical operations.
25	// - Detects branches
26	//
27	// (despite the name, this stage also handles floating point reciprocal
28	// estimates)
29	//
30	
31	module int_execute_stage(
32	    input                             clk,
33	    input                             reset,
34	
35	    // From operand_fetch_stage
36	    input vector_t                    of_operand1,
37	    input vector_t                    of_operand2,
38	    input vector_mask_t               of_mask_value,
39	    input                             of_instruction_valid,
40	    input decoded_instruction_t       of_instruction,
41	    input local_thread_idx_t          of_thread_idx,
42	    input subcycle_t                  of_subcycle,
43	
44	    // From writeback_stage
45	    input logic                       wb_rollback_en,
46	    input local_thread_idx_t          wb_rollback_thread_idx,
47	
48	    // To writeback_stage
49	    output logic                      ix_instruction_valid,
50	    output decoded_instruction_t      ix_instruction,
51	    output vector_t                   ix_result,
52	    output vector_mask_t              ix_mask_value,
53	    output local_thread_idx_t         ix_thread_idx,
54	    output logic                      ix_rollback_en,
55	    output scalar_t                   ix_rollback_pc,
56	    output subcycle_t                 ix_subcycle,
57	    output logic                      ix_privileged_op_fault,
58	
59	    // From control_registers
60	    input scalar_t                    cr_eret_address[`THREADS_PER_CORE],
61	    input                             cr_supervisor_en[`THREADS_PER_CORE],
62	
63	    // To performance_counters
64	    output logic                      ix_perf_uncond_branch,
65	    output logic                      ix_perf_cond_branch_taken,
66	    output logic                      ix_perf_cond_branch_not_taken);
67	
68	    vector_t vector_result;
69	    logic eret;
70	    logic privileged_op_fault;
71	    logic branch_taken;
72	    logic conditional_branch;
73	    logic valid_instruction;
74	
75	    genvar lane;
76	    generate
77	        for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
78	        begin : lane_alu_gen
79	            scalar_t lane_operand1;
80	            scalar_t lane_operand2;
81	            scalar_t lane_result;
82	            scalar_t difference;
83	            logic borrow;
84	            logic negative;
85	            logic overflow;
86	            logic zero;
87	            logic signed_gtr;
88	            logic[5:0] lz;
89	            logic[5:0] tz;
90	            scalar_t reciprocal;
91	            float32_t fp_operand;
92	            logic[5:0] reciprocal_estimate;
93	            logic shift_in_sign;
94	            scalar_t rshift;
95	
96	            assign lane_operand1 = of_operand1[lane];
97	            assign lane_operand2 = of_operand2[lane];
98	            assign {borrow, difference} = {1'b0, lane_operand1} - {1'b0, lane_operand2};
99	            assign negative = difference[31];
100	            assign overflow = lane_operand2[31] == negative && lane_operand1[31] != lane_operand2[31];
101	            assign zero = difference == 0;
102	            assign signed_gtr = overflow == negative;
103	
104	            // Count leading zeroes
105	            always_comb
106	            begin
107	                unique casez (lane_operand2)
108	                    32'b1???????????????????????????????: lz = 0;
109	                    32'b01??????????????????????????????: lz = 1;
110	                    32'b001?????????????????????????????: lz = 2;
111	                    32'b0001????????????????????????????: lz = 3;
112	                    32'b00001???????????????????????????: lz = 4;
113	                    32'b000001??????????????????????????: lz = 5;
114	                    32'b0000001?????????????????????????: lz = 6;
115	                    32'b00000001????????????????????????: lz = 7;
116	                    32'b000000001???????????????????????: lz = 8;
117	                    32'b0000000001??????????????????????: lz = 9;
118	                    32'b00000000001?????????????????????: lz = 10;
119	                    32'b000000000001????????????????????: lz = 11;
120	                    32'b0000000000001???????????????????: lz = 12;
121	                    32'b00000000000001??????????????????: lz = 13;
122	                    32'b000000000000001?????????????????: lz = 14;
123	                    32'b0000000000000001????????????????: lz = 15;
124	                    32'b00000000000000001???????????????: lz = 16;
125	                    32'b000000000000000001??????????????: lz = 17;
126	                    32'b0000000000000000001?????????????: lz = 18;
127	                    32'b00000000000000000001????????????: lz = 19;
128	                    32'b000000000000000000001???????????: lz = 20;
129	                    32'b0000000000000000000001??????????: lz = 21;
130	                    32'b00000000000000000000001?????????: lz = 22;
131	                    32'b000000000000000000000001????????: lz = 23;
132	                    32'b0000000000000000000000001???????: lz = 24;
133	                    32'b00000000000000000000000001??????: lz = 25;
134	                    32'b000000000000000000000000001?????: lz = 26;
135	                    32'b0000000000000000000000000001????: lz = 27;
136	                    32'b00000000000000000000000000001???: lz = 28;
137	                    32'b000000000000000000000000000001??: lz = 29;
138	                    32'b0000000000000000000000000000001?: lz = 30;
139	                    32'b00000000000000000000000000000001: lz = 31;
140	                    32'b00000000000000000000000000000000: lz = 32;
141	                    default: lz = 0;
142	                endcase
143	            end
144	
145	            // Count trailing zeroes
146	            always_comb
147	            begin
148	                unique casez (lane_operand2)
149	                    32'b00000000000000000000000000000000: tz = 32;
150	                    32'b10000000000000000000000000000000: tz = 31;
151	                    32'b?1000000000000000000000000000000: tz = 30;
152	                    32'b??100000000000000000000000000000: tz = 29;
153	                    32'b???10000000000000000000000000000: tz = 28;
154	                    32'b????1000000000000000000000000000: tz = 27;
155	                    32'b?????100000000000000000000000000: tz = 26;
156	                    32'b??????10000000000000000000000000: tz = 25;
157	                    32'b???????1000000000000000000000000: tz = 24;
158	                    32'b????????100000000000000000000000: tz = 23;
159	                    32'b?????????10000000000000000000000: tz = 22;
160	                    32'b??????????1000000000000000000000: tz = 21;
161	                    32'b???????????100000000000000000000: tz = 20;
162	                    32'b????????????10000000000000000000: tz = 19;
163	                    32'b?????????????1000000000000000000: tz = 18;
164	                    32'b??????????????100000000000000000: tz = 17;
165	                    32'b???????????????10000000000000000: tz = 16;
166	                    32'b????????????????1000000000000000: tz = 15;
167	                    32'b?????????????????100000000000000: tz = 14;
168	                    32'b??????????????????10000000000000: tz = 13;
169	                    32'b???????????????????1000000000000: tz = 12;
170	                    32'b????????????????????100000000000: tz = 11;
171	                    32'b?????????????????????10000000000: tz = 10;
172	                    32'b??????????????????????1000000000: tz = 9;
173	                    32'b???????????????????????100000000: tz = 8;
174	                    32'b????????????????????????10000000: tz = 7;
175	                    32'b?????????????????????????1000000: tz = 6;
176	                    32'b??????????????????????????100000: tz = 5;
177	                    32'b???????????????????????????10000: tz = 4;
178	                    32'b????????????????????????????1000: tz = 3;
179	                    32'b?????????????????????????????100: tz = 2;
180	                    32'b??????????????????????????????10: tz = 1;
181	                    32'b???????????????????????????????1: tz = 0;
182	                    default: tz = 0;
183	                endcase
184	            end
185	
186	            // Right shift
187	            assign shift_in_sign = of_instruction.alu_op == OP_ASHR ? lane_operand1[31] : 1'd0;
188	            assign rshift = scalar_t'({{32{shift_in_sign}}, lane_operand1} >> lane_operand2[4:0]);
189	
190	            // Reciprocal estimate
191	            assign fp_operand = lane_operand2;
192	            reciprocal_rom rom(
193	                .significand(fp_operand.significand[22:17]),
194	                .reciprocal_estimate);
195	
196	            always_comb
197	            begin
198	                if (fp_operand.exponent == 0)
199	                begin
200	                    // A subnormal will overflow the exponent field, so convert to infinity.
201	                    // This also handles division by zero.
202	                    reciprocal = {fp_operand.sign, 8'hff, 23'd0}; // inf
203	                end
204	                else if (fp_operand.exponent == 8'hff)
205	                begin
206	                    if (fp_operand.significand != 0)
207	                        reciprocal = {1'b0, 8'hff, 23'h7fffff}; // Division by NaN = NaN
208	                    else
209	                        reciprocal = {fp_operand.sign, 8'h00, 23'h000000}; // Division by +/-inf = +/-0.0
210	                end
211	                else
212	                begin
213	                    reciprocal = {fp_operand.sign, 8'd253 - fp_operand.exponent + 8'((fp_operand.significand[22:17] == 0)),
214	                        reciprocal_estimate, {17{1'b0}}};
215	                end
216	            end
217	
218	            always_comb
219	            begin
220	                unique case (of_instruction.alu_op)
221	                    OP_ASHR,
222	                    OP_SHR: lane_result = rshift;
223	                    OP_SHL: lane_result = lane_operand1 << lane_operand2[4:0];
224	                    OP_MOVE: lane_result = lane_operand2;
225	                    OP_OR: lane_result = lane_operand1 | lane_operand2;
226	                    OP_CLZ: lane_result = scalar_t'(lz);
227	                    OP_CTZ: lane_result = scalar_t'(tz);
228	                    OP_AND: lane_result = lane_operand1 & lane_operand2;
229	                    OP_XOR: lane_result = lane_operand1 ^ lane_operand2;
230	                    OP_ADD_I: lane_result = lane_operand1 + lane_operand2;
231	                    OP_SUB_I: lane_result = difference;
232	                    OP_CMPEQ_I: lane_result = {{31{1'b0}}, zero};
233	                    OP_CMPNE_I: lane_result = {{31{1'b0}}, !zero};
234	                    OP_CMPGT_I: lane_result = {{31{1'b0}}, signed_gtr && !zero};
235	                    OP_CMPGE_I: lane_result = {{31{1'b0}}, signed_gtr || zero};
236	                    OP_CMPLT_I: lane_result = {{31{1'b0}}, !signed_gtr && !zero};
237	                    OP_CMPLE_I: lane_result = {{31{1'b0}}, !signed_gtr || zero};
238	                    OP_CMPGT_U: lane_result = {{31{1'b0}}, !borrow && !zero};
239	                    OP_CMPGE_U: lane_result = {{31{1'b0}}, !borrow || zero};
240	                    OP_CMPLT_U: lane_result = {{31{1'b0}}, borrow && !zero};
241	                    OP_CMPLE_U: lane_result = {{31{1'b0}}, borrow || zero};
242	                    OP_SEXT8: lane_result = scalar_t'($signed(lane_operand2[7:0]));
243	                    OP_SEXT16: lane_result = scalar_t'($signed(lane_operand2[15:0]));
244	                    OP_SHUFFLE,
245	                    OP_GETLANE: lane_result = of_operand1[~lane_operand2];
246	                    OP_RECIPROCAL: lane_result = reciprocal;
247	                    default: lane_result = 0;
248	                endcase
249	            end
250	
251	            assign vector_result[lane] = lane_result;
252	        end
253	    endgenerate
254	
255	    assign valid_instruction = of_instruction_valid
256	        && (!wb_rollback_en || wb_rollback_thread_idx != of_thread_idx)
257	        && of_instruction.pipeline_sel == PIPE_INT_ARITH;
258	    assign eret = valid_instruction
259	        && of_instruction.branch
260	        && of_instruction.branch_type == BRANCH_ERET;
261	    assign privileged_op_fault = eret && !cr_supervisor_en[of_thread_idx];
262	
263	    always_comb
264	    begin
265	        branch_taken = 0;
266	        conditional_branch = 0;
267	
268	        if (valid_instruction
269	            && of_instruction.branch
270	            && !privileged_op_fault)
271	        begin
272	            unique case (of_instruction.branch_type)
273	                BRANCH_ZERO:
274	                begin
275	                    branch_taken = of_operand1[0] == 0;
276	                    conditional_branch = 1;
277	                end
278	
279	                BRANCH_NOT_ZERO:
280	                begin
281	                    branch_taken = of_operand1[0] != 0;
282	                    conditional_branch = 1;
283	                end
284	
285	                BRANCH_ALWAYS,
286	                BRANCH_CALL_OFFSET,
287	                BRANCH_CALL_REGISTER,
288	                BRANCH_REGISTER,
289	                BRANCH_ERET:
290	                begin
291	                    branch_taken = 1;
292	                end
293	
294	                default:
295	                    ;
296	            endcase
297	        end
298	    end
299	
300	
301	    always_ff @(posedge clk)
302	    begin
303	        ix_instruction <= of_instruction;
304	        ix_result <= vector_result;
305	        ix_mask_value <= of_mask_value;
306	        ix_thread_idx <= of_thread_idx;
307	        ix_subcycle <= of_subcycle;
308	
309	        // Branch handling
310	        unique case (of_instruction.branch_type)
311	            BRANCH_CALL_REGISTER,
312	            BRANCH_REGISTER: ix_rollback_pc <= of_operand1[0];
313	            BRANCH_ERET: ix_rollback_pc <= cr_eret_address[of_thread_idx];
314	            default:
315	                ix_rollback_pc <= of_instruction.pc + of_instruction.immediate_value;
316	        endcase
317	    end
318	
319	    always_ff @(posedge clk, posedge reset)
320	    begin
321	        if (reset)
322	        begin
323	            /*AUTORESET*/
324	            // Beginning of autoreset for uninitialized flops
325	            ix_instruction_valid <= '0;
326	            ix_perf_cond_branch_not_taken <= '0;
327	            ix_perf_cond_branch_taken <= '0;
328	            ix_perf_uncond_branch <= '0;
329	            ix_privileged_op_fault <= '0;
330	            ix_rollback_en <= '0;
331	            // End of automatics
332	        end
333	        else
334	        begin
335	            if (valid_instruction)
336	            begin
337	                ix_instruction_valid <= 1;
338	                ix_privileged_op_fault <= privileged_op_fault;
339	                ix_rollback_en <= branch_taken;
340	            end
341	            else
342	            begin
343	                ix_instruction_valid <= 0;
344	                ix_rollback_en <= 0;
345	            end
346	
347	            ix_perf_uncond_branch <= !conditional_branch && branch_taken;
348	            ix_perf_cond_branch_taken <= conditional_branch && branch_taken;
349	            ix_perf_cond_branch_not_taken <= conditional_branch && !branch_taken;
350	        end
351	    end
352	endmodule
