14	// limitations under the License.
15	//
16	
17	`include "defines.svh"
18	
19	import defines::*;
20	
21	//
22	// Instruction Pipeline Writeback Stage
23	// - Selects result from appropriate pipeline (memory, integer, floating point)
24	// - Aligns memory read results
25	// - Writes results back to register file
26	// - Handles rollbacks. Most are raised earlier in the pipeline, but it
27	//   handles them here to avoid having to reconcile multiple rollbacks in
28	//   the same cycle.
29	//   * Branch
30	//   * Data cache miss
31	//   * Exception
32	//
33	// Exceptions and interrupts are precise in this architecture. This is
34	// complicated by the fact that instructions may retire out of order because
35	// the execution pipelines have different lengths. It's also possible, after
36	// a rollback, for earlier instructions from the same thread to arrive at
37	// this stage (because they were in the longer floating point pipeline).
38	// The rollback signal does not flush later stages of the multicycle pipeline
39	// for this reason.
40	//
41	
42	module writeback_stage(
43	    input                                 clk,
44	    input                                 reset,
45	
46	    // From fp_execute_stage5 (floating point pipline)
47	    input                                 fx5_instruction_valid,
48	    input decoded_instruction_t           fx5_instruction,
49	    input vector_t                        fx5_result,
50	    input vector_mask_t                   fx5_mask_value,
51	    input local_thread_idx_t              fx5_thread_idx,
52	    input subcycle_t                      fx5_subcycle,
53	
54	    // From int_execute_stage (integer pipeline)
55	    input                                 ix_instruction_valid,
56	    input decoded_instruction_t           ix_instruction,
57	    input vector_t                        ix_result,
58	    input local_thread_idx_t              ix_thread_idx,
59	    input vector_mask_t                   ix_mask_value,
60	    input logic                           ix_rollback_en,
61	    input scalar_t                        ix_rollback_pc,
62	    input subcycle_t                      ix_subcycle,
63	    input                                 ix_privileged_op_fault,
64	
65	    // From dcache_data_stage (memory pipeline)
66	    input                                 dd_instruction_valid,
67	    input decoded_instruction_t           dd_instruction,
68	    input vector_mask_t                   dd_lane_mask,
69	    input local_thread_idx_t              dd_thread_idx,
70	    input l1d_addr_t                      dd_request_vaddr,
71	    input subcycle_t                      dd_subcycle,
72	    input                                 dd_rollback_en,
73	    input scalar_t                        dd_rollback_pc,
74	    input cache_line_data_t               dd_load_data,
75	    input                                 dd_suspend_thread,
76	    input                                 dd_io_access,
77	    input logic                           dd_trap,
78	    input trap_cause_t                    dd_trap_cause,
79	
80	    // From l1_store_queue
81	    input [CACHE_LINE_BYTES - 1:0]        sq_store_bypass_mask,
82	    input cache_line_data_t               sq_store_bypass_data,
83	    input                                 sq_store_sync_success,
84	    input                                 sq_rollback_en,
85	
86	    // From io_request_queue
87	    input scalar_t                        ior_read_value,
88	    input logic                           ior_rollback_en,
89	
90	    // From control_registers
91	    input scalar_t                        cr_creg_read_val,
92	    input scalar_t                        cr_trap_handler,
93	    input scalar_t                        cr_tlb_miss_handler,
94	    input subcycle_t                      cr_eret_subcycle[`THREADS_PER_CORE],
95	
96	    // To control_registers
97	    output logic                          wb_trap,
98	    output trap_cause_t                   wb_trap_cause,
99	    output scalar_t                       wb_trap_pc,
100	    output scalar_t                       wb_trap_access_vaddr,
101	    output subcycle_t                     wb_trap_subcycle,
102	    output syscall_index_t                wb_syscall_index,
103	    output logic                          wb_eret,
104	
105	    // Rollback signals to all stages
106	    output logic                          wb_rollback_en,
107	    output local_thread_idx_t             wb_rollback_thread_idx,
108	    output scalar_t                       wb_rollback_pc,
109	    output pipeline_sel_t                 wb_rollback_pipeline,
110	    output subcycle_t                     wb_rollback_subcycle,
111	
112	    // To operand_fetch_stage/thread_select_stage
113	    output logic                          wb_writeback_en,
114	    output local_thread_idx_t             wb_writeback_thread_idx,
115	    output logic                          wb_writeback_vector,
116	    output vector_t                       wb_writeback_value,
117	    output vector_mask_t                  wb_writeback_mask,
118	    output register_idx_t                 wb_writeback_reg,
119	    output logic                          wb_writeback_last_subcycle,
120	
121	    // To thread_select_stage
122	    output local_thread_bitmap_t          wb_suspend_thread_oh,
123	
124	    // to on_chip_debugger
125	    output logic                          wb_inst_injected,
126	
127	    // To performance_counters
128	    output logic                          wb_perf_instruction_retire,
129	    output logic                          wb_perf_store_rollback,
130	    output logic                          wb_perf_interrupt);
131	
132	    scalar_t mem_load_lane;
133	    logic[$clog2(CACHE_LINE_WORDS) - 1:0] mem_load_lane_idx;
134	    logic[7:0] byte_aligned;
135	    logic[15:0] half_aligned;
136	    logic[31:0] swapped_word_value;
137	    memory_op_t memory_op;
138	    cache_line_data_t endian_twiddled_data;
139	    logic[NUM_VECTOR_LANES - 1:0] scycle_vcompare_result;
140	    logic[NUM_VECTOR_LANES - 1:0] mcycle_vcompare_result;
141	    vector_mask_t dd_vector_lane_oh;
142	    cache_line_data_t bypassed_read_data;
143	    local_thread_bitmap_t thread_dd_oh;
144	    logic last_subcycle_dd;
145	    logic last_subcycle_ix;
146	    logic last_subcycle_fx;
147	    logic writeback_en_nxt;
148	    local_thread_idx_t writeback_thread_idx_nxt;
149	    logic writeback_vector_nxt;
150	    vector_t writeback_value_nxt;
151	    vector_mask_t writeback_mask_nxt;
152	    register_idx_t writeback_reg_nxt;
153	    logic writeback_last_subcycle_nxt;
154	
155	    //
156	    // Rollback control logic
157	    //
158	    // These signals are not registered because the next instruction may be a
159	    // memory store and we must squash it before it applies its side effects.
160	    // This stage handles all rollbacks, so there can be only one asserted at a
161	    // time.
162	    //
163	    always_comb
164	    begin
165	        wb_rollback_en = 0;
166	        wb_rollback_pc = 0;
167	        wb_rollback_thread_idx = 0;
168	        wb_rollback_pipeline = PIPE_INT_ARITH;
169	        wb_trap = 0;
170	        wb_trap_cause = {2'b0, TT_RESET};
171	        wb_rollback_subcycle = 0;
172	        wb_trap_pc = 0;
173	        wb_trap_access_vaddr = 0;
174	        wb_trap_subcycle = dd_subcycle;
175	        wb_eret = 0;
176	
177	        if (ix_instruction_valid && (ix_instruction.has_trap
178	            || ix_privileged_op_fault))
179	        begin
180	            // Fault piggybacked on instruction, which goes through the
181	            // integer pipeline, or fault detected in integer pipeline.
182	            wb_rollback_en = 1;
183	            if (ix_instruction.trap_cause.trap_type == TT_TLB_MISS)
184	                wb_rollback_pc = cr_tlb_miss_handler;
185	            else
186	                wb_rollback_pc = cr_trap_handler;
187	
188	            wb_rollback_thread_idx = ix_thread_idx;
189	            wb_rollback_pipeline = PIPE_INT_ARITH;
190	            wb_trap = 1;
191	            if (ix_privileged_op_fault)
192	                wb_trap_cause = {2'b0, TT_PRIVILEGED_OP};
193	            else
194	                wb_trap_cause = ix_instruction.trap_cause;
195	
196	            wb_trap_pc = ix_instruction.pc;
197	            wb_trap_access_vaddr = ix_instruction.pc;
198	            wb_trap_subcycle = ix_subcycle;
199	        end
200	        else if (dd_instruction_valid && dd_trap)
201	        begin
202	            // Memory access fault
203	            wb_rollback_en = 1'b1;
204	            if (dd_trap_cause.trap_type == TT_TLB_MISS)
205	                wb_rollback_pc = cr_tlb_miss_handler;
206	            else
207	                wb_rollback_pc = cr_trap_handler;
208	
209	            wb_rollback_thread_idx = dd_thread_idx;
210	            wb_rollback_pipeline = PIPE_MEM;
211	            wb_trap = 1;
212	            wb_trap_cause = dd_trap_cause;
213	            wb_trap_pc = dd_instruction.pc;
214	            wb_trap_access_vaddr = dd_request_vaddr;
215	        end
216	        else if (ix_instruction_valid && ix_rollback_en)
217	        begin
218	            // Branch rollback from integer pipeline.
219	            wb_rollback_en = 1;
220	            wb_rollback_pc = ix_rollback_pc;
221	            wb_rollback_thread_idx = ix_thread_idx;
222	            wb_rollback_pipeline = PIPE_INT_ARITH;
223	            if (ix_instruction.branch_type == BRANCH_ERET)
224	            begin
225	                wb_eret = 1;
226	                wb_rollback_subcycle = cr_eret_subcycle[ix_thread_idx];
227	            end
228	            else
229	                wb_rollback_subcycle = ix_subcycle;
230	        end
231	        else if (dd_instruction_valid && (dd_rollback_en || sq_rollback_en || ior_rollback_en))
232	        begin
233	            // Rollback from memory pipeline because of a data cache miss,
234	            // store queue full, or when an IO request is sent.
235	            wb_rollback_en = 1;
236	            wb_rollback_pc = dd_rollback_pc;
237	            wb_rollback_thread_idx = dd_thread_idx;
238	            wb_rollback_pipeline = PIPE_MEM;
239	            wb_rollback_subcycle = dd_subcycle;
240	        end
241	    end
242	
243	    assign wb_syscall_index = syscall_index_t'(ix_instruction.immediate_value);
244	
245	    // Return if this instruction was injected by the on chip debugger.
246	    always_comb
247	    begin
248	        if (ix_instruction_valid)
249	            wb_inst_injected = ix_instruction.injected;
250	        else if (dd_instruction_valid)
251	            wb_inst_injected = dd_instruction.injected;
252	        else if (fx5_instruction_valid)
253	            wb_inst_injected = fx5_instruction.injected;
254	        else
255	            wb_inst_injected = 0;
256	    end
257	
258	    idx_to_oh #(
259	        .NUM_SIGNALS(`THREADS_PER_CORE),
260	        .DIRECTION("LSB0")
261	    ) idx_to_oh_thread(
262	        .one_hot(thread_dd_oh),
263	        .index(dd_thread_idx));
264	
265	    // Suspend thread if necessary
266	    assign wb_suspend_thread_oh = (dd_suspend_thread || sq_rollback_en || ior_rollback_en)
267	        ? thread_dd_oh : local_thread_bitmap_t'(0);
268	
269	    // If there is a pending store for the value that was just read, merge it into
270	    // the data returned from the L1 data cache.
271	    genvar byte_lane;
272	    generate
273	        for (byte_lane = 0; byte_lane < CACHE_LINE_BYTES; byte_lane++)
274	        begin : lane_bypass_gen
275	            assign bypassed_read_data[byte_lane * 8+:8] = sq_store_bypass_mask[byte_lane]
276	                ? sq_store_bypass_data[byte_lane * 8+:8] : dd_load_data[byte_lane * 8+:8];
277	        end
278	    endgenerate
279	
280	    assign memory_op = dd_instruction.memory_access_type;
281	    assign mem_load_lane_idx = ~dd_request_vaddr.offset[2+:$clog2(CACHE_LINE_WORDS)];
282	    assign mem_load_lane = bypassed_read_data[mem_load_lane_idx * 32+:32];
283	
284	    // Byte memory load aligner.
285	    always_comb
286	    begin
287	        unique case (dd_request_vaddr.offset[1:0])
288	            2'd0: byte_aligned = mem_load_lane[31:24];
289	            2'd1: byte_aligned = mem_load_lane[23:16];
290	            2'd2: byte_aligned = mem_load_lane[15:8];
291	            2'd3: byte_aligned = mem_load_lane[7:0];
292	            default: byte_aligned = '0;
293	        endcase
294	    end
295	
296	    // Halfword memory load aligner.
297	    always_comb
298	    begin
299	        unique case (dd_request_vaddr.offset[1])
300	            1'd0: half_aligned = {mem_load_lane[23:16], mem_load_lane[31:24]};
301	            1'd1: half_aligned = {mem_load_lane[7:0], mem_load_lane[15:8]};
302	            default: half_aligned = '0;
303	        endcase
304	    end
305	
306	    assign swapped_word_value = {
307	        mem_load_lane[7:0],
308	        mem_load_lane[15:8],
309	        mem_load_lane[23:16],
310	        mem_load_lane[31:24]
311	    };
312	
313	    // Endian swap memory load
314	    genvar swap_word;
315	    generate
316	        for (swap_word = 0; swap_word < CACHE_LINE_BYTES / 4; swap_word++)
317	        begin : swap_word_gen
318	            assign endian_twiddled_data[swap_word * 32+:8] = bypassed_read_data[swap_word * 32 + 24+:8];
319	            assign endian_twiddled_data[swap_word * 32 + 8+:8] = bypassed_read_data[swap_word * 32 + 16+:8];
320	            assign endian_twiddled_data[swap_word * 32 + 16+:8] = bypassed_read_data[swap_word * 32 + 8+:8];
321	            assign endian_twiddled_data[swap_word * 32 + 24+:8] = bypassed_read_data[swap_word * 32+:8];
322	        end
323	    endgenerate
324	
325	    // Compress vector comparisons to one bit per lane.
326	    genvar mask_lane;
327	    generate
328	        for (mask_lane = 0; mask_lane < NUM_VECTOR_LANES; mask_lane++)
329	        begin : compare_result_gen
330	            assign scycle_vcompare_result[mask_lane] = ix_result[NUM_VECTOR_LANES - mask_lane - 1][0];
331	            assign mcycle_vcompare_result[mask_lane] = fx5_result[NUM_VECTOR_LANES - mask_lane - 1][0];
332	        end
333	    endgenerate
334	
335	    idx_to_oh #(
336	        .NUM_SIGNALS(NUM_VECTOR_LANES),
337	        .DIRECTION("LSB0")
338	    ) convert_dd_lane(
339	        .one_hot(dd_vector_lane_oh),
340	        .index(dd_subcycle));
341	
342	    assign last_subcycle_dd = dd_subcycle == dd_instruction.last_subcycle;
343	    assign last_subcycle_ix = ix_subcycle == ix_instruction.last_subcycle;
344	    assign last_subcycle_fx = fx5_subcycle == fx5_instruction.last_subcycle;
345	
346	    always_comb
347	    begin
348	        writeback_en_nxt = 0;
349	        writeback_thread_idx_nxt = 0;
350	        writeback_mask_nxt = 0;
351	        writeback_value_nxt = 0;
352	        writeback_vector_nxt = 0;
353	        writeback_reg_nxt = 0;
354	        writeback_last_subcycle_nxt = 0;
355	
356	        // wb_rollback_en is derived combinatorially from the instruction
357	        // that is about to retire, so this doesn't need to check
358	        // wb_rollback_thread_idx like other places.
359	        if (fx5_instruction_valid)
360	        begin
361	            //
362	            // Floating point pipeline result
363	            //
364	            if (fx5_instruction.has_dest && !wb_rollback_en)
365	                writeback_en_nxt = 1;
366	
367	            writeback_thread_idx_nxt = fx5_thread_idx;
368	            writeback_mask_nxt = fx5_mask_value;
369	            if (fx5_instruction.compare)
370	                writeback_value_nxt[0] = {16'd0, mcycle_vcompare_result};
371	            else
372	                writeback_value_nxt = fx5_result;
373	
374	            writeback_vector_nxt = fx5_instruction.dest_vector;
375	            writeback_reg_nxt = fx5_instruction.dest_reg;
376	            writeback_last_subcycle_nxt = last_subcycle_fx;
377	        end
378	        else if (ix_instruction_valid)
379	        begin
380	            //
381	            // Integer pipeline result
382	            //
383	            if (ix_instruction.branch
384	                && (ix_instruction.branch_type == BRANCH_CALL_OFFSET
385	                || ix_instruction.branch_type == BRANCH_CALL_REGISTER))
386	            begin
387	                // Call is a special case: it both rolls back and writes
388	                // back a register (ra)
389	                writeback_en_nxt = 1;
390	            end
391	            else if (ix_instruction.has_dest && !wb_rollback_en)
392	            begin
393	                // This is a normal, non-rolled-back instruction
394	                writeback_en_nxt = 1;
395	            end
396	
397	            writeback_thread_idx_nxt = ix_thread_idx;
398	            writeback_mask_nxt = ix_mask_value;
399	            if (ix_instruction.call)
400	                writeback_value_nxt[0] = ix_instruction.pc + 32'd4;
401	            else if (ix_instruction.compare)
402	                writeback_value_nxt[0] = {16'd0, scycle_vcompare_result};
403	            else
404	                writeback_value_nxt = ix_result;
405	
406	            writeback_vector_nxt = ix_instruction.dest_vector;
407	            writeback_reg_nxt = ix_instruction.dest_reg;
408	            writeback_last_subcycle_nxt = last_subcycle_ix;
409	        end
410	        else if (dd_instruction_valid)
411	        begin
412	            //
413	            // Memory pipeline result
414	            //
415	            writeback_en_nxt = dd_instruction.has_dest && !wb_rollback_en;
416	            writeback_thread_idx_nxt = dd_thread_idx;
417	            if (!dd_instruction.cache_control)
418	            begin
419	                if (dd_instruction.load)
420	                begin
421	                    unique case (memory_op)
422	                        MEM_B:      writeback_value_nxt[0] = scalar_t'(byte_aligned);
423	                        MEM_BX:     writeback_value_nxt[0] = scalar_t'($signed(byte_aligned));
424	                        MEM_S:      writeback_value_nxt[0] = scalar_t'(half_aligned);
425	                        MEM_SX:     writeback_value_nxt[0] = scalar_t'($signed(half_aligned));
426	                        MEM_SYNC:   writeback_value_nxt[0] = swapped_word_value;
427	                        MEM_L:
428	                        begin
429	                            // Scalar Load
430	                            if (dd_io_access)
431	                            begin
432	                                writeback_mask_nxt = {NUM_VECTOR_LANES{1'b1}};
433	                                writeback_value_nxt[0] = ior_read_value;
434	                            end
435	                            else
436	                            begin
437	                                writeback_mask_nxt = {NUM_VECTOR_LANES{1'b1}};
438	                                writeback_value_nxt[0] = swapped_word_value;
439	                            end
440	                        end
441	
442	                        MEM_CONTROL_REG:
443	                        begin
444	                            writeback_mask_nxt = {NUM_VECTOR_LANES{1'b1}};
445	                            writeback_value_nxt[0] = cr_creg_read_val;
446	                        end
447	
448	                        MEM_BLOCK,
449	                        MEM_BLOCK_M:
450	                        begin
451	                            writeback_mask_nxt = dd_lane_mask;
452	                            writeback_value_nxt = endian_twiddled_data;
453	                        end
454	
455	                        default:
456	                        begin
457	                            // Gather load
458	                            // Grab the appropriate lane.
459	                            writeback_mask_nxt = dd_vector_lane_oh & dd_lane_mask;
460	                            writeback_value_nxt = {NUM_VECTOR_LANES{swapped_word_value}};
461	                        end
462	                    endcase
463	                end
464	                else if (memory_op == MEM_SYNC)
465	                begin
466	                    // Synchronized stores are special because they write
467	                    // back (whether they were successful).
468	                    writeback_value_nxt[0] = scalar_t'(sq_store_sync_success);
469	                end
470	            end
471	
472	            writeback_vector_nxt = dd_instruction.dest_vector;
473	            writeback_reg_nxt = dd_instruction.dest_reg;
474	            writeback_last_subcycle_nxt = last_subcycle_dd;
475	        end
476	    end
477	
478	    always_ff @(posedge clk)
479	    begin
480	        wb_writeback_thread_idx <= writeback_thread_idx_nxt;
481	        wb_writeback_mask <= writeback_mask_nxt;
482	        wb_writeback_value <= writeback_value_nxt;
483	        wb_writeback_vector <= writeback_vector_nxt;
484	        wb_writeback_reg <= writeback_reg_nxt;
485	        wb_writeback_last_subcycle <= writeback_last_subcycle_nxt;
486	    end
487	
488	    always_ff @(posedge clk, posedge reset)
489	    begin
490	        if (reset)
491	            wb_writeback_en <= 0;
492	        else
493	        begin
494	            // Don't cause rollback if there isn't an instruction
495	            assert(!(sq_rollback_en && !dd_instruction_valid));
496	
497	            // Only one pipeline should attempt to retire an instruction per cycle
498	            assert($onehot0({ix_instruction_valid, dd_instruction_valid, fx5_instruction_valid}));
499	
500	            if (dd_instruction_valid && !dd_instruction.cache_control)
501	            begin
502	                if (dd_instruction.load)
503	                begin
504	                    // Loads should always have a destination register.
505	                    assert(dd_instruction.has_dest);
506	
507	                    if (memory_op == MEM_B || memory_op == MEM_BX || memory_op == MEM_S
508	                        || memory_op == MEM_SX || memory_op == MEM_SYNC || memory_op == MEM_L
509	                        || memory_op == MEM_CONTROL_REG)
510	                    begin
511	                        // Must be scalar destination
512	                        assert(!dd_instruction.dest_vector);
513	                    end
514	                    else
515	                        assert(dd_instruction.dest_vector);
516	                end
517	                else if (memory_op == MEM_SYNC)
518	                begin
519	                    // Synchronized stores are special because they write back (whether they
520	                    // were successful).
521	                    assert(dd_instruction.has_dest && !dd_instruction.dest_vector);
522	                end
523	            end
524	
525	            wb_writeback_en <= writeback_en_nxt;
526	            wb_perf_instruction_retire <= (fx5_instruction_valid || ix_instruction_valid
527	                || dd_instruction_valid) && (!wb_rollback_en
528	                || (ix_instruction_valid && ix_instruction.branch && !ix_privileged_op_fault));
529	            wb_perf_store_rollback <= sq_rollback_en;
530	            wb_perf_interrupt <= ix_instruction_valid && ix_instruction.has_trap
531	                && ix_instruction.trap_cause.trap_type == TT_INTERRUPT;
532	        end
533	    end
534	
535	`ifdef SIMULATION
536	    always_ff @(posedge clk)
537	    begin
538	        // this will happen if there is a fault and no fault handler has
539	        // been set in the control register.
540	        if (wb_trap && wb_rollback_pc == 0)
541	        begin
542	            $display("thread %0d caught trap, no handler set, cause %0d address %08x", wb_rollback_thread_idx,
543	                wb_trap_cause, wb_trap_pc);
544	            $finish;
545	        end
546	    end
547	`endif
548	endmodule
549

